alter table public.users enable row level security; drop policy if exists "own_user" on public.users; create policy "own_user" on public.users for all using (auth.uid() = id) with check (auth.uid() = id); drop policy if exists "own_trips" on public.trips; create policy "own_trips" on public.trips for all using (auth.uid() = user_id) with check (auth.uid() = user_id); drop policy if exists "own_blocks" on public.activity_blocks; create policy "own_blocks" on public.activity_blocks for all using (exists (select 1 from public.trips where id = trip_id and user_id = auth.uid())) with check (exists (select 1 from public.trips where id = trip_id and user_id = auth.uid())); drop policy if exists "own_checkins" on public.check_ins; create policy "own_checkins" on public.check_ins for all using (auth.uid() = user_id) with check (auth.uid() = user_id);